package main
import ("bytes"; "fmt"; "net/http"; "net/url"; "strings"; "time")
func SendRemoteLog(config Config, level,eventType,message string) error { form:=url.Values{}; form.Set("rustdesk_id",RustDeskID()); form.Set("hostname",Hostname()); form.Set("level",level); form.Set("event_type",eventType); form.Set("message",message); endpoint:=strings.TrimRight(config.Server,"/")+"/api/agent/log"; req,e:=http.NewRequest(http.MethodPost,endpoint,bytes.NewBufferString(form.Encode())); if e!=nil{return e}; req.Header.Set("Content-Type","application/x-www-form-urlencoded"); req.Header.Set("X-API-Key",config.AgentAPIKey); c:=&http.Client{Timeout:15*time.Second}; r,e:=c.Do(req); if e!=nil{return e}; defer r.Body.Close(); if r.StatusCode<200||r.StatusCode>=300{return fmt.Errorf("journal distant : %s",r.Status)}; return nil }
